import{_ as i,a as s}from"./chunks/devmgr1.B3qSFmcW.js";import{_ as t,c as e,a1 as l,o as n}from"./chunks/framework.CWcXGLD-.js";const o="/hinata-docs-vitepress/assets/devmgr3.DMkXyMX9.png",r="/hinata-docs-vitepress/assets/devmgr2.Ca1Ky3JY.png",u=JSON.parse('{"title":"SEGA 官方串口协议连接游戏","description":"","frontmatter":{},"headers":[],"relativePath":"SEGA/serial.md","filePath":"SEGA/serial.md"}'),p={name:"SEGA/serial.md"};function d(h,a,c,g,m,k){return n(),e("div",null,a[0]||(a[0]=[l('<h1 id="sega-官方串口协议连接游戏" tabindex="-1">SEGA 官方串口协议连接游戏 <a class="header-anchor" href="#sega-官方串口协议连接游戏" aria-label="Permalink to &quot;SEGA 官方串口协议连接游戏&quot;">​</a></h1><h2 id="食用须知" tabindex="-1">食用须知 <a class="header-anchor" href="#食用须知" aria-label="Permalink to &quot;食用须知&quot;">​</a></h2><p>使用 SEGA 官方的串口读卡器协议需要关闭 Segatools 的读卡器 hook<br>如果关闭 hook 以后游戏未成功连接到读卡器（比如某些地方设置错误），游戏便会断网，需要修好后重启游戏</p><h2 id="读卡器端口配置" tabindex="-1">读卡器端口配置 <a class="header-anchor" href="#读卡器端口配置" aria-label="Permalink to &quot;读卡器端口配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">游戏</th><th style="text-align:center;">端口号</th></tr></thead><tbody><tr><td style="text-align:center;">maimai DX</td><td style="text-align:center;">COM1</td></tr><tr><td style="text-align:center;">ONGEKI</td><td style="text-align:center;">COM1</td></tr><tr><td style="text-align:center;">CHUNITHM</td><td style="text-align:center;">COM4</td></tr></tbody></table><ol><li><p>首先确认你游玩的游戏的<strong>端口号</strong>并记下。以上是常用游戏的默认端口号，其他游戏如果使用 amdaemon 的话可以在<code>config_common.json</code>中查看</p></li><li><ol><li>打开 Windows 的 <code>设备管理器</code> ，默认情况下的排列方式是 按类型列出设备</li><li>我们首先要确保对应游戏连接读卡器的端口号是否被其他设备占用</li><li><strong>拔掉读卡器</strong>，寻找 <code>端口</code> 下拉菜单</li></ol><p><img src="'+o+'" alt="devmgr3"></p><ol start="4"><li>如果没有看到 <code>端口</code> 下拉菜单，可以直接进入下一步<br>如果有的话，下拉并检查是否有设备占用了目标端口</li><li>如果占用了端口，需要右键该设备，并依次选择 <code>属性 → 端口设置 → 高级</code></li></ol><p><img src="'+r+'" alt="devmgr2"></p><ol start="6"><li>将 COM 端口号 <strong>修改为其他的端口</strong>（比如 COM255）</li></ol></li><li><p><strong>插上读卡器</strong>，进入下图的选单（<strong>按容器列出设备</strong>）</p><p><img src="'+i+'" alt="devmgr0"></p></li><li><p>找到 <strong>HINATA</strong></p><p><img src="'+s+`" alt="devmgr1"></p></li><li><p>右键点击 <code>USB 串行设备</code>，并依次选择 并依次选择 <code>属性 → 端口设置 → 高级</code></p></li><li><p>将 <code>COM 端口号</code> 修改为对应游戏所需要的端口号。因为读卡器使用了 <em>USB CDC</em> 类来进行串口通信，正常情况下无需修改波特率设置</p></li><li><p>修改完成后需要重新插拔一次读卡器</p></li></ol><h2 id="游戏本体配置" tabindex="-1">游戏本体配置 <a class="header-anchor" href="#游戏本体配置" aria-label="Permalink to &quot;游戏本体配置&quot;">​</a></h2><ol><li>首先请确保你的游戏是<strong>已经联网</strong>的，进入游戏后能够显示一个<strong>绿色地球图标</strong>，否则请先把游戏的联网设置好，不在本文讨论范围内</li><li>打开<code>segatools.ini</code>，并按照如下方式修改：<div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">;如果没有[aime]条目则请手动添加该条目和条目下内容</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[aime]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">enable</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=0</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">;enable=0的用途是关闭掉segatools的读卡器hook，使用官方串口IO，请务必这样设置**</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">;如果有[aimeio]条目(比如使用了hinata的aimeio模式，以及mageki或nageki)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">;在前面添加&quot;;&quot;来注释掉，或者直接整段删掉</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[aimeio]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">;path=hinata.dll</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">;如果有以上条目的话请务必删除</span></span></code></pre></div></li><li>因为读卡器使用了 <em>USB CDC</em> 类来进行串口通信，正常情况下无需修改波特率设置</li><li>启动游戏</li></ol><h2 id="其他页面" tabindex="-1">其他页面 <a class="header-anchor" href="#其他页面" aria-label="Permalink to &quot;其他页面&quot;">​</a></h2><ul><li><a href="./../HCP/">调整串口模式下灯光亮度</a></li><li><a href="./aimeio.html">AimeIO 方式连接 SEGA 游戏</a></li><li><a href="./in_game_test.html">游戏内测试读卡器</a></li><li><a href="./../KONAMI/">KONAMI 游戏设置</a></li></ul>`,10)]))}const y=t(p,[["render",d]]);export{u as __pageData,y as default};
